/**
 * chartUtils.js
 * Converts raw query result data into Highcharts configuration objects
 * for bar, line, and pie chart types.
 */

// Aviation-terminal palette
const PALETTE = [
  '#f5a623', '#39d353', '#58a6ff', '#ff6b6b',
  '#c084fc', '#34d399', '#fb923c', '#e879f9',
  '#22d3ee', '#a3e635',
];

const BASE_THEME = {
  chart: {
    backgroundColor: 'transparent',
    style: { fontFamily: "'DM Sans', sans-serif" },
  },
  title:    { style: { color: '#e6edf3', fontSize: '14px', fontWeight: '500' } },
  subtitle: { style: { color: '#8b949e' } },
  legend:   { itemStyle: { color: '#8b949e' }, itemHoverStyle: { color: '#e6edf3' } },
  tooltip: {
    backgroundColor: '#131a22',
    borderColor: '#2a3f54',
    borderRadius: 6,
    style: { color: '#e6edf3', fontSize: '13px' },
  },
  credits: { enabled: false },
  colors:  PALETTE,
};

/**
 * Detect which column to use as the category axis and which as the value axis.
 * Heuristic: first string-ish column = category, first numeric column = value.
 */
function detectAxes(data) {
  if (!Array.isArray(data) || data.length === 0) return { catKey: null, valKey: null };

  const keys    = Object.keys(data[0]);
  const catKey  = keys.find(k => typeof data[0][k] === 'string') ?? keys[0];
  const valKey  = keys.find(k => typeof data[0][k] === 'number' && k !== catKey) ?? keys[1];
  return { catKey, valKey };
}

/** Format a column header for display */
function fmtLabel(key = '') {
  return key.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}

// ── Bar chart ──────────────────────────────────────────────────────────────
export function buildBarConfig(data, title = '') {
  const { catKey, valKey } = detectAxes(data);
  if (!catKey || !valKey) return null;

  const categories = data.map(r => String(r[catKey]));
  const seriesData = data.map(r => Number(r[valKey]) || 0);

  return {
    ...BASE_THEME,
    chart:   { ...BASE_THEME.chart, type: 'bar' },
    title:   { ...BASE_THEME.title, text: title },
    xAxis: {
      categories,
      labels: { style: { color: '#8b949e', fontSize: '12px' } },
      lineColor: '#1e2d3d',
      tickColor: '#1e2d3d',
    },
    yAxis: {
      title:     { text: fmtLabel(valKey), style: { color: '#8b949e' } },
      labels:    { style: { color: '#8b949e' } },
      gridLineColor: '#1e2d3d',
    },
    plotOptions: {
      bar: {
        borderRadius: 4,
        dataLabels:   { enabled: true, style: { color: '#e6edf3', fontSize: '11px', textOutline: 'none' } },
        colorByPoint: true,
      },
    },
    series: [{ name: fmtLabel(valKey), data: seriesData, showInLegend: false }],
  };
}

// ── Line chart ─────────────────────────────────────────────────────────────
export function buildLineConfig(data, title = '') {
  const { catKey, valKey } = detectAxes(data);
  if (!catKey || !valKey) return null;

  const categories = data.map(r => String(r[catKey]));
  const seriesData = data.map(r => Number(r[valKey]) || 0);

  return {
    ...BASE_THEME,
    chart:   { ...BASE_THEME.chart, type: 'line' },
    title:   { ...BASE_THEME.title, text: title },
    xAxis: {
      categories,
      labels:    { style: { color: '#8b949e', fontSize: '12px' }, rotation: -30 },
      lineColor: '#1e2d3d',
      tickColor: '#1e2d3d',
    },
    yAxis: {
      title:     { text: fmtLabel(valKey), style: { color: '#8b949e' } },
      labels:    { style: { color: '#8b949e' } },
      gridLineColor: '#1e2d3d',
    },
    plotOptions: {
      line: {
        marker:    { enabled: true, radius: 4 },
        lineWidth: 2,
      },
    },
    series: [{
      name: fmtLabel(valKey),
      data: seriesData,
      color: '#f5a623',
    }],
  };
}

// ── Pie chart ──────────────────────────────────────────────────────────────
export function buildPieConfig(data, title = '') {
  const { catKey, valKey } = detectAxes(data);
  if (!catKey || !valKey) return null;

  const pieData = data.map((r, i) => ({
    name:  String(r[catKey]),
    y:     Number(r[valKey]) || 0,
    color: PALETTE[i % PALETTE.length],
  }));

  return {
    ...BASE_THEME,
    chart: { ...BASE_THEME.chart, type: 'pie' },
    title: { ...BASE_THEME.title, text: title },
    plotOptions: {
      pie: {
        allowPointSelect: true,
        cursor:           'pointer',
        innerSize:        '40%',    // donut
        borderColor:      '#080c10',
        borderWidth:      2,
        dataLabels: {
          enabled:  true,
          format:   '<b>{point.name}</b>: {point.percentage:.1f}%',
          style:    { color: '#e6edf3', fontSize: '12px', textOutline: 'none' },
        },
      },
    },
    series: [{ name: fmtLabel(valKey), data: pieData }],
  };
}

// ── Dispatcher ─────────────────────────────────────────────────────────────
export function buildChartConfig(chartType, data, question = '') {
  if (!Array.isArray(data) || data.length === 0) return null;

  const title = question.length > 60 ? question.slice(0, 57) + '…' : question;

  switch (chartType) {
    case 'bar':  return buildBarConfig(data, title);
    case 'line': return buildLineConfig(data, title);
    case 'pie':  return buildPieConfig(data, title);
    default:     return null;
  }
}
